import{_ as t,o as a,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Random Image API और Public Gallery","description":"","frontmatter":{},"headers":[],"relativePath":"hi/Other/random-image-api-and-public-gallery.md","filePath":"hi/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),i={name:"hi/Other/random-image-api-and-public-gallery.md"};function o(l,e,s,c,n,p){return a(),d("div",null,[...e[0]||(e[0]=[r(`<h1 id="random-image-api-और-public-gallery" tabindex="-1">Random Image API और Public Gallery <a class="header-anchor" href="#random-image-api-और-public-gallery" aria-label="Permalink to &quot;Random Image API और Public Gallery&quot;">​</a></h1><p>दोनों features यहाँ configure होते हैं:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>Random Image API selected directories से एक random file return करता है। यह site backgrounds, avatar rotation या external pages से random image calls के लिए उपयोगी है।</p><p>Enable करने के बाद यह इस्तेमाल करें:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="random-image-api-settings" tabindex="-1">Random Image API Settings <a class="header-anchor" href="#random-image-api-settings" aria-label="Permalink to &quot;Random Image API Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td><code>/random</code> endpoint on या off करता है। Disabled होने पर access forbidden है।</td></tr><tr><td>Directories</td><td>Random API किन directories का इस्तेमाल कर सकता है, यह limit करता है। जो directories यहाँ शामिल नहीं हैं, API उन्हें इस्तेमाल नहीं कर सकता।</td></tr><tr><td>Call demo</td><td>Random API links generate करता है जिन्हें आप direct copy कर सकते हैं।</td></tr></tbody></table><p>आप multiple directories select कर सकते हैं। उदाहरण के लिए, अगर केवल <code>/landscape/</code> और <code>/portrait/</code> allowed हैं, तो random API सिर्फ उन directories और उनके subdirectories से files चुन सकता है।</p><h2 id="random-image-api-parameters" tabindex="-1">Random Image API Parameters <a class="header-anchor" href="#random-image-api-parameters" aria-label="Permalink to &quot;Random Image API Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Example</th><th>Purpose</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>Random directory specify करता है।</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>Media type specify करता है। <code>image</code>, <code>video</code>, <code>audio</code> या comma-separated combinations इस्तेमाल करें।</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>Image orientation filter करता है। <code>portrait</code>, <code>landscape</code> या <code>auto</code> इस्तेमाल करें।</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Return format। Empty मतलब redirect, <code>url</code> plain text URL return करता है, <code>json</code> JSON return करता है।</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td><code>type=url</code> के साथ full URL return करने के लिए इस्तेमाल होता है।</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Age rating से filter करता है।</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>केवल वे files return करता है जिनमें ये tags हों।</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>इन tags वाली files exclude करता है।</td></tr></tbody></table><h2 id="return-formats" tabindex="-1">Return Formats <a class="header-anchor" href="#return-formats" aria-label="Permalink to &quot;Return Formats&quot;">​</a></h2><p><code>type</code> के बिना API सीधे random file URL पर redirect करता है।</p><p><code>type=url</code> के साथ text URL return होता है।</p><p><code>type=json</code> के साथ file information return होती है, जिसमें file URL, file ID, file name, file type, tags, rating और related metadata शामिल होते हैं।</p><h2 id="access-rules" tabindex="-1">Access Rules <a class="header-anchor" href="#access-rules" aria-label="Permalink to &quot;Access Rules&quot;">​</a></h2><p>Random Image API public access rules follow करता है:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Directory restriction</td><td>केवल allowed directories की files select हो सकती हैं।</td></tr><tr><td>Blocklist</td><td>Blocklisted files random pool से exclude होती हैं।</td></tr><tr><td>Allowlist mode</td><td>Enabled होने पर केवल public access के लिए allowed files return होती हैं।</td></tr><tr><td>Age rating</td><td>R12, R16, R18 और similar content current access mode से filter होता है।</td></tr></tbody></table><p>Filtering के बाद कोई file match न हो, तो API no matching result return करता है।</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>Random Image API speed बेहतर करने के लिए directory candidate pools cache करता है।</p><p>Files बदलने के बाद ImgBed directory cache version update करता है, और बाद की requests candidate pool rebuild करती हैं। Empty directories को repeated queries से बचाने के लिए थोड़े समय के लिए cache किया जाता है।</p><h2 id="public-gallery" tabindex="-1">Public Gallery <a class="header-anchor" href="#public-gallery" aria-label="Permalink to &quot;Public Gallery&quot;">​</a></h2><p>Public gallery उन directories के लिए read-only public browsing page देती है जिन्हें आप visitors को दिखाना चाहते हैं।</p><p>Enable करने के बाद visitors यह खोल सकते हैं:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="public-gallery-settings" tabindex="-1">Public Gallery Settings <a class="header-anchor" href="#public-gallery-settings" aria-label="Permalink to &quot;Public Gallery Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td>Public gallery on या off करता है। Disabled होने पर visitors इसे browse नहीं कर सकते।</td></tr><tr><td>Image loading mode</td><td>Previews original images इस्तेमाल करें या thumbnails, यह control करता है।</td></tr><tr><td>Open directories</td><td>Visitors किन directories को access कर सकते हैं, यह set करता है।</td></tr></tbody></table><h2 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Purpose</th></tr></thead><tbody><tr><td>Original</td><td>Visitor page original files directly load करता है।</td></tr><tr><td>Thumbnail</td><td>Visitor page fast loading के लिए thumbnails prefer करता है।</td></tr></tbody></table><h2 id="open-directories" tabindex="-1">Open Directories <a class="header-anchor" href="#open-directories" aria-label="Permalink to &quot;Open Directories&quot;">​</a></h2><p>Open directories तय करती हैं कि visitors क्या देख सकते हैं।</p><p>उदाहरण:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Visitors फिर ये access कर सकते हैं:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Subdirectories भी open की जा सकती हैं, जैसे <code>/2026/lucky/</code>। जो directories open नहीं हैं, visitors उनसे blocked रहेंगे।</p><h2 id="public-gallery-features" tabindex="-1">Public Gallery Features <a class="header-anchor" href="#public-gallery-features" aria-label="Permalink to &quot;Public Gallery Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Browse directories</td><td>Open directories में files और subdirectories देखें।</td></tr><tr><td>Search</td><td>File name, file ID या tags से search करें।</td></tr><tr><td>Type filter</td><td>Images, videos, audio या other files filter करें।</td></tr><tr><td>Tag filter</td><td>Selected tags include या exclude करें।</td></tr><tr><td>Orientation filter</td><td>Landscape या portrait images filter करें।</td></tr><tr><td>Time filter</td><td>Upload time range से filter करें।</td></tr><tr><td>Extension filter</td><td>File extension से filter करें।</td></tr><tr><td>Copy link</td><td>File access links copy करें।</td></tr><tr><td>Media preview</td><td>Visitor page पर images, videos और audio देखें या play करें।</td></tr></tbody></table><h2 id="public-gallery-access-rules" tabindex="-1">Public Gallery Access Rules <a class="header-anchor" href="#public-gallery-access-rules" aria-label="Permalink to &quot;Public Gallery Access Rules&quot;">​</a></h2><p>Public gallery भी public access rules follow करती है:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Open directories</td><td>केवल allowed directories दिखती हैं।</td></tr><tr><td>Access mode</td><td>Content current age-rating access mode से filter होता है।</td></tr><tr><td>Allowlist mode</td><td>Enabled होने पर केवल public access के लिए allowed files दिखती हैं।</td></tr><tr><td>Blocklist</td><td>Blocklisted files hidden रहती हैं।</td></tr></tbody></table>`,43)])])}const m=t(i,[["render",o]]);export{u as __pageData,m as default};
